Now I'll create the complete SyncForge AI single-page web app with all the requested features.

<write_to_file>
<path>syncforge-ai.html</path>
<content><!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>SyncForge AI - Detect Code Drift from Requirements</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
            background: #0f0f0f;
            color: #e5e5e5;
            line-height: 1.6;
            min-height: 100vh;
        }

        .container {
            max-width: 1400px;
            margin: 0 auto;
            padding: 20px;
        }

        header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 20px 0;
            border-bottom: 1px solid #2a2a2a;
            margin-bottom: 30px;
        }

        .header-content {
            flex: 1;
        }

        h1 {
            font-size: 32px;
            font-weight: 700;
            color: #3b82f6;
            margin-bottom: 5px;
        }

        .tagline {
            color: #888;
            font-size: 14px;
        }

        .settings-icon {
            width: 40px;
            height: 40px;
            background: #1a1a1a;
            border: 1px solid #2a2a2a;
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s;
        }

        .settings-icon:hover {
            background: #2a2a2a;
            border-color: #3b82f6;
        }

        .settings-icon svg {
            width: 20px;
            height: 20px;
            fill: #888;
        }

        .input-screen {
            display: block;
        }

        .results-screen {
            display: none;
        }

        .panels {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 20px;
            margin-bottom: 20px;
        }

        .panel {
            background: #1a1a1a;
            border: 1px solid #2a2a2a;
            border-radius: 12px;
            padding: 20px;
        }

        .panel h2 {
            font-size: 18px;
            margin-bottom: 15px;
            color: #fff;
        }

        textarea {
            width: 100%;
            height: 400px;
            background: #0f0f0f;
            border: 1px solid #2a2a2a;
            border-radius: 8px;
            padding: 15px;
            color: #e5e5e5;
            font-family: 'Courier New', monospace;
            font-size: 13px;
            resize: vertical;
            outline: none;
        }

        textarea:focus {
            border-color: #3b82f6;
        }

        .analyze-btn {
            width: 100%;
            padding: 18px;
            background: #3b82f6;
            color: white;
            border: none;
            border-radius: 12px;
            font-size: 18px;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
        }

        .analyze-btn:hover {
            background: #2563eb;
            transform: translateY(-2px);
        }

        .analyze-btn:disabled {
            background: #2a2a2a;
            color: #666;
            cursor: not-allowed;
            transform: none;
        }

        .drift-score {
            background: #1a1a1a;
            border: 1px solid #2a2a2a;
            border-radius: 12px;
            padding: 30px;
            text-align: center;
            margin-bottom: 30px;
        }

        .score-label {
            font-size: 14px;
            color: #888;
            margin-bottom: 10px;
        }

        .score-value {
            font-size: 48px;
            font-weight: 700;
            margin-bottom: 10px;
        }

        .score-green { color: #10b981; }
        .score-yellow { color: #f59e0b; }
        .score-red { color: #ef4444; }

        .results-container {
            display: grid;
            grid-template-columns: 1fr 400px;
            gap: 20px;
        }

        .requirements-list {
            display: flex;
            flex-direction: column;
            gap: 15px;
        }

        .requirement-card {
            background: #1a1a1a;
            border: 1px solid #2a2a2a;
            border-radius: 12px;
            padding: 20px;
        }

        .requirement-header {
            display: flex;
            align-items: flex-start;
            gap: 12px;
            margin-bottom: 10px;
        }

        .status-badge {
            padding: 6px 12px;
            border-radius: 6px;
            font-size: 12px;
            font-weight: 600;
            white-space: nowrap;
        }

        .status-covered {
            background: #10b98120;
            color: #10b981;
        }

        .status-partial {
            background: #f59e0b20;
            color: #f59e0b;
        }

        .status-missing {
            background: #ef444420;
            color: #ef4444;
        }

        .requirement-text {
            flex: 1;
            font-size: 15px;
            line-height: 1.5;
        }

        .requirement-explanation {
            color: #888;
            font-size: 13px;
            margin-top: 8px;
            padding-left: 12px;
            border-left: 2px solid #2a2a2a;
        }

        .slack-panel {
            background: #1a1a1a;
            border: 1px solid #2a2a2a;
            border-radius: 12px;
            overflow: hidden;
            height: fit-content;
            position: sticky;
            top: 20px;
        }

        .slack-header {
            background: #0f0f0f;
            padding: 15px;
            border-bottom: 1px solid #2a2a2a;
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .slack-avatar {
            width: 36px;
            height: 36px;
            background: #3b82f6;
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 700;
            font-size: 18px;
            color: white;
        }

        .slack-bot-name {
            font-weight: 600;
            font-size: 15px;
        }

        .slack-bot-label {
            background: #2a2a2a;
            color: #888;
            padding: 2px 6px;
            border-radius: 4px;
            font-size: 11px;
            margin-left: 5px;
        }

        .slack-content {
            padding: 20px;
        }

        .slack-message {
            background: #0f0f0f;
            border: 1px solid #2a2a2a;
            border-radius: 8px;
            padding: 15px;
            margin-bottom: 10px;
        }

        .slack-timestamp {
            color: #666;
            font-size: 12px;
            margin-top: 10px;
        }

        .slack-alert {
            color: #ef4444;
            font-weight: 600;
            margin-bottom: 10px;
        }

        .slack-item {
            margin: 8px 0;
            padding-left: 15px;
            font-size: 13px;
            line-height: 1.6;
        }

        .back-btn {
            padding: 12px 24px;
            background: #2a2a2a;
            color: white;
            border: 1px solid #3a3a3a;
            border-radius: 8px;
            font-size: 14px;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
            margin-bottom: 20px;
        }

        .back-btn:hover {
            background: #3a3a3a;
        }

        .modal {
            display: none;
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.8);
            z-index: 1000;
            align-items: center;
            justify-content: center;
        }

        .modal.active {
            display: flex;
        }

        .modal-content {
            background: #1a1a1a;
            border: 1px solid #2a2a2a;
            border-radius: 12px;
            padding: 30px;
            max-width: 500px;
            width: 90%;
        }

        .modal-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 20px;
        }

        .modal-title {
            font-size: 20px;
            font-weight: 600;
        }

        .close-btn {
            background: none;
            border: none;
            color: #888;
            font-size: 24px;
            cursor: pointer;
            padding: 0;
            width: 30px;
            height: 30px;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .close-btn:hover {
            color: #fff;
        }

        .modal label {
            display: block;
            margin-bottom: 8px;
            color: #888;
            font-size: 14px;
        }

        .modal input {
            width: 100%;
            padding: 12px;
            background: #0f0f0f;
            border: 1px solid #2a2a2a;
            border-radius: 8px;
            color: #e5e5e5;
            font-size: 14px;
            margin-bottom: 15px;
        }

        .modal input:focus {
            outline: none;
            border-color: #3b82f6;
        }

        .save-btn {
            width: 100%;
            padding: 12px;
            background: #3b82f6;
            color: white;
            border: none;
            border-radius: 8px;
            font-size: 14px;
            font-weight: 600;
            cursor: pointer;
        }

        .save-btn:hover {
            background: #2563eb;
        }

        .loading {
            text-align: center;
            padding: 40px;
        }

        .spinner {
            border: 3px solid #2a2a2a;
            border-top: 3px solid #3b82f6;
            border-radius: 50%;
            width: 50px;
            height: 50px;
            animation: spin 1s linear infinite;
            margin: 0 auto 20px;
        }

        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }

        .error-message {
            background: #ef444420;
            border: 1px solid #ef4444;
            color: #ef4444;
            padding: 15px;
            border-radius: 8px;
            margin-bottom: 20px;
        }

        @media (max-width: 1024px) {
            .panels {
                grid-template-columns: 1fr;
            }

            .results-container {
                grid-template-columns: 1fr;
            }

            .slack-panel {
                position: static;
            }
        }
    </style>
</head>
<body>
    <div class="container">
        <header>
            <div class="header-content">
                <h1>SyncForge AI</h1>
                <p class="tagline">Know when your code drifts from requirements</p>
            </div>
            <div class="settings-icon" onclick="openSettings()">
                <svg viewBox="0 0 24 24">
                    <path d="M19.14,12.94c0.04-0.3,0.06-0.61,0.06-0.94c0-0.32-0.02-0.64-0.07-0.94l2.03-1.58c0.18-0.14,0.23-0.41,0.12-0.61 l-1.92-3.32c-0.12-0.22-0.37-0.29-0.59-0.22l-2.39,0.96c-0.5-0.38-1.03-0.7-1.62-0.94L14.4,2.81c-0.04-0.24-0.24-0.41-0.48-0.41 h-3.84c-0.24,0-0.43,0.17-0.47,0.41L9.25,5.35C8.66,5.59,8.12,5.92,7.63,6.29L5.24,5.33c-0.22-0.08-0.47,0-0.59,0.22L2.74,8.87 C2.62,9.08,2.66,9.34,2.86,9.48l2.03,1.58C4.84,11.36,4.8,11.69,4.8,12s0.02,0.64,0.07,0.94l-2.03,1.58 c-0.18,0.14-0.23,0.41-0.12,0.61l1.92,3.32c0.12,0.22,0.37,0.29,0.59,0.22l2.39-0.96c0.5,0.38,1.03,0.7,1.62,0.94l0.36,2.54 c0.05,0.24,0.24,0.41,0.48,0.41h3.84c0.24,0,0.44-0.17,0.47-0.41l0.36-2.54c0.59-0.24,1.13-0.56,1.62-0.94l2.39,0.96 c0.22,0.08,0.47,0,0.59-0.22l1.92-3.32c0.12-0.22,0.07-0.47-0.12-0.61L19.14,12.94z M12,15.6c-1.98,0-3.6-1.62-3.6-3.6 s1.62-3.6,3.6-3.6s3.6,1.62,3.6,3.6S13.98,15.6,12,15.6z"/>
                </svg>
            </div>
        </header>

        <div class="input-screen" id="inputScreen">
            <div class="panels">
                <div class="panel">
                    <h2>Requirements</h2>
                    <textarea id="requirementsInput" placeholder="Enter requirements, one per line...">1. User can register with email and password
2. User can log in with email and password
3. Password reset must support email and SMS
4. All login attempts must be audit logged
5. User session expires after 30 minutes of inactivity</textarea>
                </div>
                <div class="panel">
                    <h2>Code Diff</h2>
                    <textarea id="diffInput" placeholder="Paste your git diff or code snippet...">+ function resetPasswordByEmail(email) {
+   const token = generateToken();
+   sendEmail(email, token);
+   return token;
+ }
+ function loginUser(email, password) {
+   const user = db.findUser(email);
+   if (!user) throw new Error('Not found');
+   return generateSession(user);
+ }</textarea>
                </div>
            </div>
            <button class="analyze-btn" onclick="analyzeDrift()">Analyze Drift</button>
        </div>

        <div class="results-screen" id="resultsScreen">
            <button class="back-btn" onclick="goBack()">← Back</button>

            <div id="errorContainer"></div>

            <div id="loadingContainer" class="loading" style="display: none;">
                <div class="spinner"></div>
                <p>Analyzing drift with Claude AI...</p>
            </div>

            <div id="resultsContainer" style="display: none;">
                <div class="drift-score">
                    <div class="score-label">Coverage Score</div>
                    <div class="score-value" id="scoreValue">0%</div>
                </div>

                <div class="results-container">
                    <div class="requirements-list" id="requirementsList"></div>
                    <div class="slack-panel">
                        <div class="slack-header">
                            <div class="slack-avatar">S</div>
                            <div>
                                <div class="slack-bot-name">
                                    SyncForge Bot
                                    <span class="slack-bot-label">APP</span>
                                </div>
                            </div>
                        </div>
                        <div class="slack-content">
                            <div class="slack-message">
                                <div class="slack-alert">⚠️ Drift Alert</div>
                                <div id="slackAlerts"></div>
                                <div class="slack-timestamp" id="slackTimestamp"></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <div class="modal" id="settingsModal">
        <div class="modal-content">
            <div class="modal-header">
                <h3 class="modal-title">API Settings</h3>
                <button class="close-btn" onclick="closeSettings()">×</button>
            </div>
            <label for="apiKeyInput">Anthropic API Key</label>
            <input type="password" id="apiKeyInput" placeholder="sk-ant-...">
            <button class="save-btn" onclick="saveApiKey()">Save</button>
        </div>
    </div>

    <script>
        let apiKey = '';

        function openSettings() {
            document.getElementById('settingsModal').classList.add('active');
            document.getElementById('apiKeyInput').value = apiKey;
        }

        function closeSettings() {
            document.getElementById('settingsModal').classList.remove('active');
        }

        function saveApiKey() {
            apiKey = document.getElementById('apiKeyInput').value.trim();
            closeSettings();
        }

        function goBack() {
            document.getElementById('inputScreen').style.display = 'block';
            document.getElementById('resultsScreen').style.display = 'none';
        }

        function showError(message) {
            const errorContainer = document.getElementById('errorContainer');
            errorContainer.innerHTML = `<div class="error-message">${message}</div>`;
        }

        function clearError() {
            document.getElementById('errorContainer').innerHTML = '';
        }

        async function analyzeDrift() {
            const requirements = document.getElementById('requirementsInput').value.trim();
            const diff = document.getElementById('diffInput').value.trim();

            if (!requirements || !diff) {
                alert('Please enter both requirements and code diff.');
                return;
            }

            if (!apiKey) {
                alert('Please set your Anthropic API key in settings first.');
                openSettings();
                return;
            }

            document.getElementById('inputScreen').style.display = 'none';
            document.getElementById('resultsScreen').style.display = 'block';
            document.getElementById('loadingContainer').style.display = 'block';
            document.getElementById('resultsContainer').style.display = 'none';
            clearError();

            const requirementsArray = requirements.split('\n').filter(r => r.trim());
            const numberedRequirements = requirementsArray.map((req, idx) => `${idx + 1}. ${req.replace(/^\d+\.\s*/, '')}`).join('\n');

            const prompt = `You are analyzing code drift from requirements. 

Requirements:
${numberedRequirements}

Code Diff:
${diff}

Analyze each requirement against the code diff and determine:
- "covered" if the requirement is fully addressed in the diff
- "partial" if the requirement is only partially addressed
- "missing" if the requirement has no coverage in the diff

Also calculate an overall drift_score from 0-100, where 100 means all requirements are covered.

Return ONLY a valid JSON object with this exact structure (no markdown, no code blocks):
{
  "drift_score": 62,
  "requirements": [
    {
      "req_id": 1,
      "req_text": "User can register with email and password",
      "status": "missing",
      "explanation": "No registration functionality found in the diff"
    }
  ]
}`;

            try {
                const response = await fetch('https://api.anthropic.com/v1/messages', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'x-api-key': apiKey,
                        'anthropic-version': '2023-06-01'
                    },
                    body: JSON.stringify({
                        model: 'claude-sonnet-4-20250514',
                        max_tokens: 4096,
                        messages: [{
                            role: 'user',
                            content: prompt
                        }]
                    })
                });

                if (!response.ok) {
                    const errorData = await response.json();
                    throw new Error(errorData.error?.message || `API error: ${response.status}`);
                }

                const data = await response.json();
                const content = data.content[0].text;

                let jsonContent = content.trim();
                if (jsonContent.startsWith('```json')) {
                    jsonContent = jsonContent.replace(/```json\n?/g, '').replace(/```\n?/g, '');
                } else if (jsonContent.startsWith('```')) {
                    jsonContent = jsonContent.replace(/```\n?/g, '');
                }

                const result = JSON.parse(jsonContent);
                displayResults(result);
            } catch (error) {
                console.error('Error:', error);
                document.getElementById('loadingContainer').style.display = 'none';
                showError(`Error: ${error.message}`);
            }
        }

        function displayResults(result) {
            document.getElementById('loadingContainer').style.display = 'none';
            document.getElementById('resultsContainer').style.display = 'block';

            const score = result.drift_score;
            const scoreElement = document.getElementById('scoreValue');
            scoreElement.textContent = `${score}%`;

            if (score > 80) {
                scoreElement.className = 'score-value score-green';
            } else if (score >= 50) {
                scoreElement.className = 'score-value score-yellow';
            } else {
                scoreElement.className = 'score-value score-red';
            }

            const requirementsList = document.getElementById('requirementsList');
            requirementsList.innerHTML = '';

            const slackAlerts = [];

            result.requirements.forEach(req => {
                const card = document.createElement('div');
                card.className = 'requirement-card';

                let statusBadge = '';
                let statusClass = '';

                if (req.status === 'covered') {
                    statusBadge = '✅ Covered';
                    statusClass = 'status-covered';
                } else if (req.status === 'partial') {
                    statusBadge = '⚠️ Partial';
                    statusClass = 'status-partial';
                    slackAlerts.push({ text: req.req_text, status: 'partial', explanation: req.explanation });
                } else {
                    statusBadge = '❌ Missing';
                    statusClass = 'status-missing';
                    slackAlerts.push({ text: req.req_text, status: 'missing', explanation: req.explanation });
                }

                card.innerHTML = `
                    <div class="requirement-header">
                        <span class="status-badge ${statusClass}">${statusBadge}</span>
                        <div class="requirement-text">${req.req_text}</div>
                    </div>
                    <div class="requirement-explanation">${req.explanation}</div>
                `;

                requirementsList.appendChild(card);
            });

            const slackAlertsContainer = document.getElementById('slackAlerts');
            if (slackAlerts.length === 0) {
                slackAlertsContainer.innerHTML = '<div style="color: #10b981;">✅ All requirements covered! No drift detected.</div>';
            } else {
                let alertsHtml = '<div style="margin-bottom: 10px;">The following requirements need attention:</div>';
                slackAlerts.forEach(alert => {
                    const icon = alert.status === 'partial' ? '⚠️' : '❌';
                    alertsHtml += `<div class="slack-item">${icon} ${alert.text}</div>`;
                });
                slackAlertsContainer.innerHTML = alertsHtml;
            }

            const now = new Date();
            const timeStr = now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
            document.getElementById('slackTimestamp').textContent = timeStr;
        }

        document.getElementById('settingsModal').addEventListener('click', function(e) {
            if (e.target === this) {
                closeSettings();
            }
        });
    </script>
</body>
</html></content>
