                        status = 'partial';
                        explanation = 'Partial implementation detected';
                        whatsMissing = 'Complete implementation of all aspects of this requirement';
                        partialCount++;
                    } else {
                        explanation = 'No clear implementation found for this requirement';
                        whatsMissing = 'Implement functionality to address this requirement';
                    }
                }

                results.push({
                    req_id: reqId,
                    req_text: req,
                    status: status,
                    explanation: explanation,
                    whats_missing: whatsMissing
                });
            });

            const totalReqs = requirementsArray.length;
            const driftScore = Math.round((coveredCount * 100 + partialCount * 50) / totalReqs);

            const missingItems = results.filter(r => r.status === 'missing');
            const partialItems = results.filter(r => r.status === 'partial');

            let slackMessage = '';
            if (missingItems.length === 0 && partialItems.length === 0) {
                slackMessage = `Hey @developer 👋 Great work!\n\n✅ All requirements are covered in your latest push.\n\nYour code is aligned with the spec. Ready to open that PR! 🚀`;
            } else {
                slackMessage = `Hey @developer 👋 Just caught some drift on your latest push.\n\n`;

                missingItems.forEach(item => {
                    slackMessage += `❌ ${item.req_id} — ${item.req_text}\n`;
                });

                partialItems.forEach(item => {
                    slackMessage += `⚠️ ${item.req_id} — ${item.req_text}\n`;
                });

                if (coveredCount > 0) {
                    slackMessage += `\nEverything else looks solid. Fix these before opening your PR and you're good to go 🚀`;
                } else {
                    slackMessage += `\nReview these gaps before opening your PR 🔍`;
                }
            }

            return {
                drift_score: driftScore,
                requirements: results,
                slack_message: slackMessage
            };
        }

        function extractKeywords(text) {
            const stopWords = ['the', 'a', 'an', 'and', 'or', 'but', 'in', 'with', 'to', 'for', 'of', 'on', 'at', 'from', 'by', 'can', 'must', 'should', 'be', 'is', 'are'];
            return text.split(/\s+/)
                .filter(word => word.length > 3 && !stopWords.includes(word))
                .slice(0, 5);
        }

        function displayResults(result) {
            showScreen('resultsScreen');

            const score = result.drift_score;
            const scoreElement = document.getElementById('scoreValue');
            const messageElement = document.getElementById('scoreMessage');

            scoreElement.textContent = `${score}%`;

            if (score > 80) {
                scoreElement.className = 'score-value score-green';
                messageElement.textContent = 'Looking good — minor gaps to address';
            } else if (score >= 50) {
                scoreElement.className = 'score-value score-yellow';
                messageElement.textContent = 'Gaps detected — review before PR';
            } else {
                scoreElement.className = 'score-value score-red';
                messageElement.textContent = 'Significant drift — do not merge yet';
            }

            const requirementsList = document.getElementById('requirementsList');
            requirementsList.innerHTML = '';

            result.requirements.forEach((req) => {
                const card = document.createElement('div');
                card.className = 'requirement-card';

                let statusBadge = '';
                let statusClass = '';

                if (req.status === 'covered') {
                    statusBadge = '✅ Covered';
                    statusClass = 'status-covered';
                } else if (req.status === 'partial') {
                    statusBadge = '⚠️ Partial';
                    statusClass = 'status-partial';
                } else {
                    statusBadge = '❌ Missing';
                    statusClass = 'status-missing';
                }

                let whatsMissingHtml = '';
                if (req.whats_missing) {
                    whatsMissingHtml = `
                        <div class="whats-missing">
                            <strong>What's missing:</strong>
                            ${req.whats_missing}
                        </div>
                    `;
                }

                card.innerHTML = `
                    <div class="req-header">
                        <span class="req-id">${req.req_id}</span>
                        <span class="status-badge ${statusClass}">${statusBadge}</span>
                    </div>
                    <div class="req-text">${req.req_text}</div>
                    <div class="req-explanation">${req.explanation}</div>
                    ${whatsMissingHtml}
                `;

                requirementsList.appendChild(card);
            });

            slackMessageText = result.slack_message;
            const slackMessageElement = document.getElementById('slackMessage');
            slackMessageElement.innerHTML = result.slack_message.split('\n').map(line => `<p>${line}</p>`).join('');

            const now = new Date();
            const timeStr = now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
            document.getElementById('slackTimestamp').textContent = `Today at ${timeStr}`;
        }

        function copySlackMessage() {
            if (!slackMessageText) {
                showToast('No message to copy');
                return;
            }

            navigator.clipboard.writeText(slackMessageText).then(() => {
                showToast('Slack message copied to clipboard!');
            }).catch(err => {
                console.error('Failed to copy:', err);
                showToast('Failed to copy message');
            });
        }
    </script>
</body>
