    <script>
        const codeState = {
            emailReset: true,
            smsReset: false,
            googleOAuth: false,
            auditLogging: 'partial',
            sessionTimeout: false,
            twoFactorSMS: false
        };

        let requirements = [];

        function initRequirements() {
            const cards = document.querySelectorAll('.requirement-card');
            requirements = Array.from(cards).map((card, index) => ({
                id: card.dataset.id,
                reqId: card.querySelector('.req-id').textContent,
                text: card.querySelector('.req-text').textContent
            }));

            cards.forEach(card => {
                const textDiv = card.querySelector('.req-text');
                textDiv.addEventListener('focus', () => {
                    card.classList.add('editing');
                });
                textDiv.addEventListener('blur', () => {
                    card.classList.remove('editing');
                    const id = card.dataset.id;
                    requirements[id].text = textDiv.textContent;
                });
            });
        }

        function syncChanges() {
            document.getElementById('loadingPanel').classList.add('active');
            document.getElementById('driftScore').classList.remove('active');
            document.getElementById('resultsPanel').classList.remove('active');
            document.getElementById('slackPanel').classList.remove('active');
            document.getElementById('qaPanel').classList.remove('active');
            document.getElementById('prPanel').classList.remove('active');

            animateLoadingSteps();

            setTimeout(() => {
                const analysis = analyzeRequirements();
                displayResults(analysis);
            }, 3500);
        }

        function animateLoadingSteps() {
            const steps = ['step1', 'step2', 'step3', 'step4'];
            steps.forEach((step, index) => {
                setTimeout(() => {
                    document.getElementById(step).classList.add('active');
                    if (index > 0) {
                        document.getElementById(steps[index - 1]).classList.remove('active');
                        document.getElementById(steps[index - 1]).classList.add('complete');
                    }
                }, index * 800);
            });
        }

        function analyzeRequirements() {
            const results = [];
            let coveredCount = 0;
            let partialCount = 0;
            let missingCount = 0;

            requirements.forEach(req => {
                const text = req.text.toLowerCase();
                let status = 'missing';
                let covered = [];
                let missing = [];

                if (text.includes('password reset')) {
                    if (text.includes('email') && !text.includes('sms')) {
                        if (codeState.emailReset) {
                            status = 'covered';
                            covered.push('Email reset implemented');
                            coveredCount++;
                        } else {
                            missing.push('Email reset not implemented');
                        }
                    } else if (text.includes('email') && text.includes('sms')) {
                        if (codeState.emailReset && codeState.smsReset) {
                            status = 'covered';
                            covered.push('Email and SMS reset implemented');
                            coveredCount++;
                        } else if (codeState.emailReset) {
                            status = 'partial';
                            covered.push('Email reset implemented');
                            missing.push('SMS reset not implemented');
                            partialCount++;
                        } else {
                            missing.push('Email and SMS reset not implemented');
                            missingCount++;
                        }
                    }
                } else if (text.includes('google') && text.includes('oauth')) {
                    if (codeState.googleOAuth) {
                        status = 'covered';
                        covered.push('Google OAuth integration complete');
                        coveredCount++;
                    } else {
                        missing.push('Google OAuth not implemented');
                        missingCount++;
                    }
                } else if (text.includes('audit') && text.includes('log')) {
                    if (codeState.auditLogging === 'full') {
                        status = 'covered';
                        covered.push('Comprehensive audit logging active');
                        coveredCount++;
                    } else if (codeState.auditLogging === 'partial') {
                        status = 'partial';
                        covered.push('Basic logging exists');
                        missing.push('Full audit trail not implemented');
                        partialCount++;
                    } else {
                        missing.push('No audit logging found');
                        missingCount++;
                    }
                } else if (text.includes('session') && text.includes('timeout')) {
                    if (codeState.sessionTimeout) {
                        status = 'covered';
                        covered.push('Session timeout configured');
                        coveredCount++;
                    } else {
                        missing.push('Session timeout not implemented');
                        missingCount++;
                    }
                } else if (text.includes('two-factor') || text.includes('2fa')) {
                    if (codeState.twoFactorSMS) {
                        status = 'covered';
                        covered.push('Two-factor authentication active');
                        coveredCount++;
                    } else {
                        missing.push('Two-factor authentication not implemented');
                        missingCount++;
                    }
                } else {
                    missing.push('Implementation not found');
                    missingCount++;
                }

                results.push({
                    reqId: req.reqId,
                    text: req.text,
                    status: status,
                    covered: covered,
                    missing: missing
                });
            });

            const total = requirements.length;
            const driftScore = Math.round((coveredCount * 100 + partialCount * 50) / total);

            return {
                driftScore: driftScore,
                results: results,
                coveredCount: coveredCount,
                partialCount: partialCount,
                missingCount: missingCount
            };
        }

        function displayResults(analysis) {
            document.getElementById('loadingPanel').classList.remove('active');
            document.getElementById('driftScore').classList.add('active');
            document.getElementById('resultsPanel').classList.add('active');

            const scoreElement = document.getElementById('scoreValue');
            const messageElement = document.getElementById('scoreMessage');
            const score = analysis.driftScore;

            scoreElement.textContent = `${score}%`;

            if (score > 80) {
                scoreElement.className = 'score-value score-green';
                messageElement.textContent = 'Looking good — minor gaps to address';
            } else if (score >= 50) {
                scoreElement.className = 'score-value score-yellow';
                messageElement.textContent = 'Gaps detected — review before PR';
            } else {
                scoreElement.className = 'score-value score-red';
                messageElement.textContent = 'Significant drift — do not merge yet';
            }

            const resultsList = document.getElementById('resultsList');
            resultsList.innerHTML = '';

            analysis.results.forEach(result => {
                const card = document.createElement('div');
                card.className = 'result-card';

                let statusBadge = '';
                let statusClass = '';

                if (result.status === 'covered') {
                    statusBadge = '✅ Covered';
                    statusClass = 'status-covered';
                } else if (result.status === 'partial') {
                    statusBadge = '⚠️ Partial';
                    statusClass = 'status-partial';
                } else {
                    statusBadge = '❌ Missing';
                    statusClass = 'status-missing';
                }

                let detailsHtml = '<div class="result-detail">';
                result.covered.forEach(item => {
                    detailsHtml += `<div>✔ ${item}</div>`;
                });
                result.missing.forEach(item => {
                    detailsHtml += `<div>❌ ${item}</div>`;
                });
                detailsHtml += '</div>';

                card.innerHTML = `
                    <div class="result-header">
                        <span class="result-req-id">${result.reqId}</span>
                        <span class="status-badge ${statusClass}">${statusBadge}</span>
                    </div>
                    <div class="result-text">${result.text}</div>
                    ${detailsHtml}
                `;

                resultsList.appendChild(card);
            });

            generateSlackNotification(analysis);
            generateQAStatus(analysis);
            generatePRAnalysis(analysis);
        }

        function generateSlackNotification(analysis) {
            const slackPanel = document.getElementById('slackPanel');
            const slackMessage = document.getElementById('slackMessage');

            const issues = analysis.results.filter(r => r.status !== 'covered');

            if (issues.length === 0) {
                slackMessage.innerHTML = `
                    <div class="slack-alert" style="color: #22c55e;">✅ All Clear</div>
                    <p>All requirements from Notion are fully implemented.</p>
                    <p>Code is aligned with spec. Ready to merge! 🚀</p>
                    <div class="slack-footer">Assigned to: @dev_ana</div>
                `;
            } else {
                let issuesHtml = '';
                issues.forEach(issue => {
                    const icon = issue.status === 'partial' ? '⚠️' : '❌';
                    issuesHtml += `<div class="slack-item">${icon} ${issue.reqId} — ${issue.text}</div>`;
                });

                slackMessage.innerHTML = `
                    <div class="slack-alert">📋 SyncForge Alert</div>
                    <p>Requirements updated from Notion</p>
                    ${issuesHtml}
                    <p style="margin-top: 12px;">Files affected:</p>
                    <div class="slack-item">- auth.js</div>
                    <div class="slack-item">- resetPassword.js</div>
                    <p style="margin-top: 12px;">Please update before PR.</p>
                    <div class="slack-footer">Assigned to: @dev_ana</div>
                `;
            }

            slackPanel.classList.add('active');
        }

        function generateQAStatus(analysis) {
            const qaPanel = document.getElementById('qaPanel');
            const qaContent = document.getElementById('qaContent');

            const isReady = analysis.missingCount === 0 && analysis.partialCount === 0;

            if (isReady) {
                qaContent.innerHTML = `
                    <div class="qa-status qa-ready">✅ READY FOR TESTING</div>
                    <p style="font-size: 14px; margin-bottom: 12px;">Feature: Authentication System</p>
                    <div class="qa-list">
                        <div class="qa-list-item">✔ All requirements implemented</div>
                        <div class="qa-list-item">✔ Code coverage verified</div>
                        <div class="qa-list-item">✔ Ready for QA testing</div>
                    </div>
                `;
            } else {
                const missing = analysis.results.filter(r => r.status === 'missing' || r.status === 'partial');
                let missingHtml = '';
                missing.forEach(item => {
                    missingHtml += `<div class="qa-list-item">❌ ${item.text}</div>`;
                });

                qaContent.innerHTML = `
                    <div class="qa-status qa-not-ready">❌ NOT READY</div>
                    <p style="font-size: 14px; margin-bottom: 12px;">Feature: Authentication System</p>
                    <div class="qa-list">
                        <div style="font-weight: 600; margin-bottom: 8px; font-size: 13px;">Missing:</div>
                        ${missingHtml}
                    </div>
                    <p style="margin-top: 12px; font-size: 13px; color: #f59e0b;">Recommendation: Block testing</p>
                `;
            }

            qaPanel.classList.add('active');
        }

        function generatePRAnalysis(analysis) {
            const prPanel = document.getElementById('prPanel');
            const prContent = document.getElementById('prContent');

            let statusClass = '';
            let statusText = '';

            if (analysis.driftScore > 80) {
                statusClass = 'pr-merge';
                statusText = '✅ READY TO MERGE';
            } else if (analysis.driftScore >= 50) {
                statusClass = 'pr-review';
                statusText = '⚠️ NEEDS REVIEW';
            } else {
                statusClass = 'pr-block';
                statusText = '❌ DO NOT MERGE';
            }

            const issues = analysis.results.filter(r => r.status !== 'covered');
            let issuesHtml = '';
            issues.forEach(issue => {
                const icon = issue.status === 'partial' ? '⚠️' : '❌';
                issuesHtml += `<div class="pr-issue">${icon} ${issue.text}</div>`;
            });

            prContent.innerHTML = `
                <div class="pr-status ${statusClass}">${statusText}</div>
                <p style="font-size: 14px; margin-bottom: 12px;">Drift Score: ${analysis.driftScore}%</p>
                ${issuesHtml ? `<div class="pr-issues">${issuesHtml}</div>` : '<p style="color: #22c55e; font-size: 13px;">All requirements covered ✓</p>'}
            `;

            prPanel.classList.add('active');
        }

        initRequirements();
    </script>
