# 🧠 DRIFT ANALYSIS ENGINE

```javascript id="drift_engine"
function runDriftAnalysis() {
  let results = [];
  let covered = 0;

  state.requirements.forEach(req => {
    let status = "missing";
    let explanation = "";

    const text = req.text.toLowerCase();

    // EMAIL RESET
    if (text.includes("email") && state.codeState.emailReset) {
      status = "covered";
    }

    // SMS RESET
    if (text.includes("sms")) {
      if (state.codeState.smsReset) {
        status = "covered";
      } else {
        status = "missing";
        explanation = "SMS reset flow not implemented";
      }
    }

    // GOOGLE LOGIN
    if (text.includes("google")) {
      if (state.codeState.googleLogin) {
        status = "covered";
      } else {
        status = "missing";
      }
    }

    // AUDIT LOGGING
    if (text.includes("audit")) {
      if (state.codeState.auditLogging === "partial") {
        status = "partial";
        explanation = "Only email logs implemented, SMS missing";
      }
    }

    if (status === "covered") covered++;

    req.status = status;
    req.explanation = explanation;

    results.push(req);
  });

  let score = Math.round((covered / state.requirements.length) * 100);

  return { results, score };
}
