        .code-keyword { color: #569cd6; }
        .code-function { color: #dcdcaa; }
        .code-string { color: #ce9178; }
        .code-comment { color: #6a9955; }

        .dev-notification {
            background: #1a1d21;
            border: 1px solid #2a2a2a;
            border-left: 3px solid #f59e0b;
            border-radius: 6px;
            padding: 12px;
            margin-bottom: 12px;
            animation: slideIn 0.3s ease-out;
        }

        @keyframes slideIn {
            from {
                transform: translateX(-20px);
                opacity: 0;
            }
            to {
                transform: translateX(0);
                opacity: 1;
            }
        }

        .notif-header {
            display: flex;
            align-items: center;
            gap: 8px;
            margin-bottom: 8px;
            font-weight: 600;
            font-size: 13px;
        }

        .notif-body {
            font-size: 12px;
            color: #d1d2d3;
            line-height: 1.5;
        }

        .notif-meta {
            font-size: 11px;
            color: #666;
            margin-top: 8px;
        }

        /* QA PANEL (DASHBOARD STYLE) */
        .qa-score {
            background: #141414;
            border: 1px solid #2a2a2a;
            border-radius: 6px;
            padding: 20px;
            text-align: center;
            margin-bottom: 16px;
        }

        .qa-score-value {
            font-size: 48px;
            font-weight: 700;
            margin-bottom: 8px;
        }

        .score-green { color: #22c55e; }
        .score-yellow { color: #f59e0b; }
        .score-red { color: #ef4444; }

        .qa-score-label {
            font-size: 12px;
            color: #888;
        }

        .qa-section {
            margin-bottom: 20px;
        }

        .qa-section-title {
            font-size: 13px;
            font-weight: 600;
            color: #888;
            margin-bottom: 12px;
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }

        .qa-item {
            background: #141414;
            border: 1px solid #2a2a2a;
            border-radius: 6px;
            padding: 12px;
            margin-bottom: 8px;
            display: flex;
            align-items: center;
            gap: 12px;
        }

        .qa-status-icon {
            font-size: 16px;
        }

        .qa-item-content {
            flex: 1;
        }

        .qa-item-title {
            font-size: 13px;
            color: #e5e5e5;
            margin-bottom: 4px;
        }

        .qa-item-detail {
            font-size: 11px;
            color: #666;
        }

        .qa-badge {
            padding: 4px 8px;
            border-radius: 4px;
            font-size: 11px;
            font-weight: 600;
        }

        .badge-ready {
            background: rgba(34, 197, 94, 0.15);
            color: #22c55e;
        }

        .badge-blocked {
            background: rgba(239, 68, 68, 0.15);
            color: #ef4444;
        }

        .badge-partial {
            background: rgba(245, 158, 11, 0.15);
            color: #f59e0b;
        }

        .loading-overlay {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.8);
            display: none;
            align-items: center;
            justify-content: center;
            z-index: 1000;
        }

        .loading-overlay.active {
            display: flex;
        }

        .loading-content {
            background: #141414;
            border: 1px solid #2a2a2a;
            border-radius: 8px;
            padding: 40px;
            text-align: center;
            max-width: 400px;
        }

        .loading-spinner {
            width: 50px;
            height: 50px;
            border: 3px solid #2a2a2a;
            border-top: 3px solid #3b82f6;
            border-radius: 50%;
            animation: spin 1s linear infinite;
            margin: 0 auto 24px;
        }

        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }

        .loading-text {
            font-size: 14px;
            color: #888;
        }

        @media (max-width: 1200px) {
            .workspace {
                grid-template-columns: 1fr;
                overflow-y: auto;
            }

            .panel {
                border-right: none;
                border-bottom: 1px solid #2a2a2a;
                height: auto;
            }
        }
    </style>
</head>
<body>
    <div class="top-bar">
        <div class="logo">
            <h1>SyncForge AI</h1>
            <span class="badge">REAL-TIME DEVOPS</span>
        </div>
        <div class="sync-status">
            <span class="sync-indicator"></span>
            <span>Live Sync Active</span>
        </div>
    </div>

    <div class="workspace">
        <!-- PM PANEL (NOTION) -->
        <div class="panel pm-panel">
            <div class="panel-header">
                <div class="panel-icon">📄</div>
                <div class="panel-title">
                    <div class="panel-name">Product Manager</div>
                    <div class="panel-subtitle">Notion Requirements</div>
                </div>
            </div>
            <div class="panel-content" id="pmContent">
                <div id="notionCards"></div>
                <button class="sync-button" onclick="syncChanges()">🔄 Sync to Team</button>
            </div>
        </div>

        <!-- DEV PANEL (VS CODE) -->
        <div class="panel dev-panel">
            <div class="panel-header">
                <div class="panel-icon">👨‍💻</div>
                <div class="panel-title">
                    <div class="panel-name">Developer</div>
                    <div class="panel-subtitle">VS Code + Notifications</div>
                </div>
            </div>
            <div class="vscode-header">
                <div class="vscode-tab active">auth.js</div>
                <div class="vscode-tab">resetPassword.js</div>
            </div>
            <div class="panel-content" style="padding: 0;">
                <div id="devNotifications" style="padding: 16px;"></div>
                <div class="code-view" id="codeView">
                    <div class="code-line">
                        <span class="line-number">1</span>
                        <span class="code-content"><span class="code-keyword">function</span> <span class="code-function">resetPasswordByEmail</span>(email) {</span>
                    </div>
                    <div class="code-line">
                        <span class="line-number">2</span>
                        <span class="code-content">  <span class="code-keyword">const</span> token = <span class="code-function">generateToken</span>();</span>
                    </div>
                    <div class="code-line">
                        <span class="line-number">3</span>
                        <span class="code-content">  <span class="code-function">sendEmail</span>(email, token);</span>
                    </div>
                    <div class="code-line">
                        <span class="line-number">4</span>
                        <span class="code-content">  <span class="code-keyword">return</span> token;</span>
                    </div>
                    <div class="code-line">
                        <span class="line-number">5</span>
                        <span class="code-content">}</span>
                    </div>
                    <div class="code-line">
                        <span class="line-number">6</span>
                        <span class="code-content"></span>
                    </div>
                    <div class="code-line">
                        <span class="line-number">7</span>
                        <span class="code-content"><span class="code-comment">// TODO: Add SMS reset support</span></span>
                    </div>
                    <div class="code-line">
                        <span class="line-number">8</span>
                        <span class="code-content"><span class="code-comment">// TODO: Implement audit logging</span></span>
                    </div>
                </div>
            </div>
        </div>

        <!-- QA PANEL (DASHBOARD) -->
        <div class="panel qa-panel">
            <div class="panel-header">
                <div class="panel-icon">🧪</div>
                <div class="panel-title">
                    <div class="panel-name">QA Engineer</div>
                    <div class="panel-subtitle">Test Dashboard</div>
                </div>
            </div>
            <div class="panel-content" id="qaContent">
                <div class="qa-score">
                    <div class="qa-score-value score-red" id="qaScore">0%</div>
                    <div class="qa-score-label">Test Coverage</div>
                </div>
                <div id="qaItems"></div>
            </div>
        </div>
    </div>

    <div class="loading-overlay" id="loadingOverlay">
        <div class="loading-content">
            <div class="loading-spinner"></div>
            <div class="loading-text">Syncing across team...</div>
        </div>
    </div>

    <script>
        // EVENT BUS - Simulates real-time communication
        const EventBus = {
            emit(event, data) {
                window.dispatchEvent(new CustomEvent(event, { detail: data }));
            },
            on(event, callback) {
                window.addEventListener(event, (e) => callback(e.detail));
            }
        };

        // STATE
        let state = {
            requirements: [
                {
                    id: "REQ-012",
                    text: "Password reset via email and SMS",
                    owner: "ana",
                    status: "unknown"
                },
                {
                    id: "REQ-013",
                    text: "Login with Google OAuth",
                    owner: "mike",
                    status: "unknown"
                },
                {
                    id: "REQ-014",
                    text: "Audit logging for all auth events",
                    owner: "ana",
                    status: "unknown"
                },
                {
                    id: "REQ-015",
                    text: "Session timeout after 30 minutes",
                    owner: "sarah",
                    status: "unknown"
                }
            ],
            codeState: {
                emailReset: true,
                smsReset: false,
                googleOAuth: false,
                auditLogging: false,
                sessionTimeout: false
            }
        };

        // INIT PM PANEL
        function initPMPanel() {
            const container = document.getElementById('notionCards');
            container.innerHTML = '';

            state.requirements.forEach((req, index) => {
                const card = document.createElement('div');
                card.className = 'notion-card';
                card.innerHTML = `
                    <div class="notion-header">
                        <div class="req-id">${req.id}</div>
                        <div class="req-owner">@${req.owner}</div>
                    </div>
                    <div class="notion-text" contenteditable="true">${req.text}</div>
                `;

                const textDiv = card.querySelector('.notion-text');
                textDiv.addEventListener('focus', () => card.classList.add('editing'));
                textDiv.addEventListener('blur', () => {
                    card.classList.remove('editing');
                    state.requirements[index].text = textDiv.textContent;
                });

                container.appendChild(card);
            });
        }

        // SYNC CHANGES
        function syncChanges() {
            document.getElementById('loadingOverlay').classList.add('active');

            setTimeout(() => {
                document.getElementById('loadingOverlay').classList.remove('active');

                const analysis = analyzeRequirements();

                EventBus.emit('REQUIREMENTS_SYNCED', analysis);

                updateDevPanel(analysis);
                updateQAPanel(analysis);
            }, 2000);
        }

        // ANALYZE REQUIREMENTS
        function analyzeRequirements() {
            let results = [];
            let covered = 0;

            state.requirements.forEach(req => {
                const text = req.text.toLowerCase();
                let status = 'missing';
                let message = '';

                if (text.includes('password reset')) {
                    if (text.includes('sms') && !state.codeState.smsReset) {
                        status = 'partial';
                        message = 'Email reset implemented, but SMS support is missing';
                    } else if (state.codeState.emailReset) {
                        status = 'covered';
                        covered++;
                    }
                } else if (text.includes('google') && text.includes('oauth')) {
                    if (!state.codeState.googleOAuth) {
                        status = 'missing';
                        message = 'Google OAuth integration not implemented';
                    }
                } else if (text.includes('audit') && text.includes('log')) {
                    if (!state.codeState.auditLogging) {
                        status = 'missing';
                        message = 'Audit logging not implemented';
                    }
                } else if (text.includes('session') && text.includes('timeout')) {
                    if (!state.codeState.sessionTimeout) {
                        status = 'missing';
                        message = 'Session timeout not configured';
                    }
                }

                results.push({
                    ...req,
                    status,
                    message
                });
            });

            const score = Math.round((covered / state.requirements.length) * 100);

            return { results, score };
        }

        // UPDATE DEV PANEL
        function updateDevPanel(analysis) {
            const container = document.getElementById('devNotifications');
            container.innerHTML = '';

            const issues = analysis.results.filter(r => r.status !== 'covered');

            if (issues.length === 0) {
                container.innerHTML = `
                    <div class="dev-notification" style="border-left-color: #22c55e;">
                        <div class="notif-header">✅ All Requirements Covered</div>
                        <div class="notif-body">Your implementation matches all requirements. Ready to commit!</div>
                    </div>
                `;
            } else {
                issues.forEach((issue, index) => {
                    setTimeout(() => {
                        const notif = document.createElement('div');
                        notif.className = 'dev-notification';
                        notif.style.borderLeftColor = issue.status === 'partial' ? '#f59e0b' : '#ef4444';

                        notif.innerHTML = `
                            <div class="notif-header">
                                ${issue.status === 'partial' ? '⚠️' : '❌'} ${issue.id} Updated
                            </div>
                            <div class="notif-body">${issue.message || 'Implementation required'}</div>
                            <div class="notif-meta">Assigned to: @${issue.owner} • From: Notion</div>
                        `;

                        container.appendChild(notif);
                    }, index * 500);
                });
            }
        }

        // UPDATE QA PANEL
        function updateQAPanel(analysis) {
            const scoreEl = document.getElementById('qaScore');
            const itemsEl = document.getElementById('qaItems');

            scoreEl.textContent = analysis.score + '%';
            scoreEl.className = 'qa-score-value ' + 
                (analysis.score > 80 ? 'score-green' : 
                 analysis.score >= 50 ? 'score-yellow' : 'score-red');

            itemsEl.innerHTML = `
                <div class="qa-section">
                    <div class="qa-section-title">Test Status</div>
                    ${analysis.results.map(req => `
                        <div class="qa-item">
                            <div class="qa-status-icon">
                                ${req.status === 'covered' ? '✅' : 
                                  req.status === 'partial' ? '⚠️' : '❌'}
                            </div>
                            <div class="qa-item-content">
                                <div class="qa-item-title">${req.id}</div>
                                <div class="qa-item-detail">${req.text}</div>
                            </div>
                            <div class="qa-badge ${
                                req.status === 'covered' ? 'badge-ready' : 
                                req.status === 'partial' ? 'badge-partial' : 'badge-blocked'
                            }">
                                ${req.status === 'covered' ? 'READY' : 
                                  req.status === 'partial' ? 'PARTIAL' : 'BLOCKED'}
                            </div>
                        </div>
                    `).join('')}
                </div>
                <div class="qa-section">
                    <div class="qa-section-title">Recommendation</div>
                    <div class="qa-item">
                        <div class="qa-item-content">
                            <div class="qa-item-title">
                                ${analysis.score === 100 ? '✅ Ready for Testing' : 
                                  analysis.score >= 50 ? '⚠️ Partial Testing Only' : 
                                  '❌ Block Testing'}
                            </div>
                            <div class="qa-item-detail">
                                ${analysis.score === 100 ? 'All requirements implemented' : 
                                  'Some requirements are incomplete'}
                            </div>
                        </div>
                    </div>
                </div>
            `;
        }

        // LISTEN TO EVENTS
        EventBus.on('REQUIREMENTS_SYNCED', (data) => {
            console.log('Requirements synced:', data);
        });

        // INIT
        initPMPanel();

        // Auto-sync on load to show initial state
        setTimeout(() => {
            syncChanges();
        }, 500);
    </script>
</body>
</html></content>
